SELECT p.*, m.name AS author, m.email AS author_email, (SELECT COUNT(*) FROM comments c WHERE c.bno = p.bno) AS comment_count, EXISTS(SELECT 1 FROM post_likes pl WHERE pl.bno = p.bno AND pl.mno = #{mno}) AS liked FROM posts p JOIN members m ON m.mno = p.mno
p.hidden = 0 AND p.board = #{board}
ORDER BY p.bno DESC LIMIT #{size} OFFSET #{offset}
